Actionscript.script:
NGIO.scoreboardComponent = this;

// default action is loading data
if (this.action === undefined) this.action = "Load Data";

// sort by slot id by default
if (this.sort_by === undefined) this.sort_by = "Slot ID";

// show visual slot numbers by default
if (this.show_slot_numbers === undefined) this.show_slot_numbers = true;

// use native objects (instead of raw strng data) by default
if (this.use_raw === undefined) this.use_raw = false;

// default handler functions
if (this.onClose === undefined) this.onClose = function() {};
if (this.onSlotSaved === undefined) this.onSlotSaved = function(error) { if (error == undefined) error = null; };
if (this.onSlotLoaded === undefined) this.onSlotLoaded = function(_data, error) { if (error == undefined) error = null; };
if (this.onSlotCleared === undefined) this.onSlotCleared = function(error) { if (error == undefined) error = null; };

this.setData = function(_data) {
	this.dataToSave = _data;
};

// supporter accounts can only 10 save slots
this.max_slots = 10;

this.saveSlots = [];

this.dispose = function() {
	NGIO.scoreboardComponent = null;
	_this.onClose = null;
	_this.onSlotSaved = null;
	_this.onSlotLoaded = null;
}

this.onUnload = this.dispose;

this.doOnClose = function() {
	this.onClose();
	this._visible = false;
}

// get save slots from AppState
var sortMe = NGIO.getSaveSlots();

// if we have no slot information, assume null
if (sortMe === undefined || sortMe === null || sortMe.length < 1) {
	this.saveSlots = null;
	this.gotoAndStop('error');
} else {
	// Sort save slots in sortMe based on this.sort_by
	if (this.sort_by === "Last Updated") {
		sortMe.sort(function(a, b) {
			var at:Number = (a && a.timestamp != null) ? Number(a.timestamp) : 0;
			var bt:Number = (b && b.timestamp != null) ? Number(b.timestamp) : 0;
			if (at > bt) return -1; // descending
			if (at < bt) return 1;
			return 0;
		});
	} else {
		sortMe.sort(function(a, b) {
			var ai:Number = (a && a.id != null) ? Number(a.id) : 0;
			var bi:Number = (b && b.id != null) ? Number(b.id) : 0;
			if (ai < bi) return -1; // ascending
			if (ai > bi) return 1;
			return 0;
		});
	}

	// ready to use now!
	this.saveSlots = sortMe;
	this.gotoAndStop('display');
}

// lock all the unselected bars so they can't be clicked on
this.lockOtherBars = function(slot_id, selected_bar):Void {
	var _min = Math.min(this.max_slots, this.saveSlots.length);
	for(var i=0; i<_min; i++) {
		var _bar = this.bars['bar_'+i];
		if (_bar.slot_id === undefined || _bar.slot_id === null || _bar.slot_id < 1) continue;

		var _slot = NGIO.getSaveSlot(_bar.slot_id);
		if (_slot.hasData() && _bar !== selected_bar) {
			_bar.gotoAndStop('locked');
		}
	}
}

this.onSlotSelected = function(slot_id, bar):Void {

	var slot = NGIO.getSaveSlot(slot_id);
	if (!slot) throw new Error("Could not find save slot with id "+slot_id);

	var method;

	// handle loading mode
	if (this.action === 'Load Data') {

		if (!slot.hasData()) throw new Error("Could not load empty slot with id "+slot_id);
		bar.gotoAndStop('loading');
		this.lockOtherBars(slot_id, bar);

		method = this.use_raw ? 'loadDataRaw':'loadData';
		slot[method](function(_data, error) {
			if (this.onSlotLoaded) this.onSlotLoaded(_data, error);

			_this.gotoAndStop('success');
		}, this);

	// handle save mode
	} else {

		// empty slots need no manual confirmation
		if (!slot.hasData()) {
			this.onSlotReplaceConfirmed(slot_id, bar);

		// prompt to overwrite existing data
		} else {
			this.confirm.show('replace');
			this.confirm.slot_id = slot_id;
			this.confirm.bar = bar;
		}
	}
}

this.onSlotReplaceConfirmed = function(slot_id, bar):Void {

	bar.gotoAndStop('saving');
	this.lockOtherBars(slot_id, bar);

	var slot = NGIO.getSaveSlot(slot_id);
	if (!slot) throw new Error("Could not find save slot with id " + slot_id);

	if (this.dataToSave === undefined) throw new Error('You must provide data to save using saveSlotManager.setData(data)');

	var method = this.use_raw ? 'saveDataRaw' : 'saveData';

	// if we have no data, treat this as a delete
	if (this.dataToSave === null || this.dataToSave === "") {
		slot.clearData(function(error) {
			if (this.onSlotLoaded) this.onSlotSaved(error);

			_this.gotoAndStop('success');
		}, this);
	} else {
		slot[method](this.dataToSave, function(error) {
			if (this.onSlotSaved) this.onSlotSaved(error);

			_this.gotoAndStop('success');
		}, this);
	}

	// prevent any accidental double saves
	this.dataToSave = undefined;
}

this.onSlotDeleted = function(slot_id, bar):Void {
	this.confirm.show('clear');
	this.confirm.slot_id = slot_id;
	this.confirm.bar = bar;
}

this.onSlotDeleteConfirmed = function(slot_id, bar):Void {

	var slot = NGIO.getSaveSlot(slot_id);

	if (this.action === "Load Data") {
		bar.gotoAndStop('no_data');
		bar.slotId.text = this.show_slot_numbers ? String(slot.id) : "";
	} else {
		bar.slotId.text = this.show_slot_numbers ? String(slot.id) : "";
		bar.saveDate.text = "";
		bar.fileSize.text = "";
		bar.saveMsg.text = "New File";
	}

	slot.clearData(function(error) {
		if (_this.onSlotCleared) _this.onSlotCleared();
	}, this);
}

this.header.text = this.action === "Load Data" ? "Select Slot To Load" : "Select Slot To Save";

for (var i=0; i<this.max_slots; i++) {
	var slot = this.saveSlots[i];

	if (i >= this.saveSlots.length) {
		this.bars['bar_'+i].gotoAndStop('reset');
	} else if (!slot.hasData() && this.action === "Load Data") {
		this.bars['bar_'+i].gotoAndStop('no_data');
		this.bars['bar_'+i].slotId.text = this.show_slot_numbers ? String(slot.id) : "";
		this.bars['bar_'+i].slot_id = slot.id;
	} else {

		var saveDate = new Date(slot.timestamp * 1000);
		var dateString:String = "";
		var sizeString:String = "";
		var msgString:String = "";

		if (slot.hasData()) {
			var months:Array = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", 
						"Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

			// 2. Calculate 12-hour format and AM/PM
			var hours24:Number = saveDate.getHours();
			var ampm:String = (hours24 >= 12) ? "PM" : "AM";
			var hours12:Number = hours24 % 12;
			if (hours12 == 0) hours12 = 12; // Handle midnight/noon

			// 3. Pad minutes with a leading zero if needed
			var minutes:String = (saveDate.getMinutes() < 10) ? "0" + saveDate.getMinutes() : String(saveDate.getMinutes());

			// 4. Assemble the string
			dateString = months[saveDate.getMonth()] + " " + saveDate.getDate() + ", " +
									saveDate.getFullYear() + " - " + hours12 + ":" + minutes + " " + ampm;



			// 1 MB = 1024 * 1024 = 1,048,576 bytes
			if (slot.size >= 1048576) {
				var mb:Number = Math.ceil((slot.size / 1048576) * 100) / 100;
				sizeString = mb + " mb";
			} else {
				// 1 KB = 1024 bytes
				var kb:Number = Math.ceil((slot.size / 1024) * 100) / 100;
				sizeString = kb + " kb";
			}
		} else {
			msgString = "New File";
			this.bars['bar_'+i].deleteBtn._visible = false;
		}

		this.bars['bar_'+i].slotId.text = this.show_slot_numbers ? String(slot.id) : "";
		this.bars['bar_'+i].saveDate.text = dateString;
		this.bars['bar_'+i].fileSize.text = sizeString;
		this.bars['bar_'+i].saveMsg.text = msgString;

		this.bars['bar_'+i].slot_id = slot.id;
	}
}

stop();
